def get_oidc_config():
    """Fetch and cache the OpenID Connect discovery document."""
    if _oidc_config_cache:
        return _oidc_config_cache

    discovery_url = f"{OIDC_ISSUER.rstrip('/')}/.well-known/openid-configuration"
    resp = requests.get(discovery_url, timeout=10)
    resp.raise_for_status()
    config = resp.json()

    required_fields = [
        "authorization_endpoint",
        "token_endpoint",
        "jwks_uri",
        "issuer",
    ]
    for field in required_fields:
        if field not in config:
            raise RuntimeError(f"OIDC discovery document missing required field: {field}")

    if config["issuer"].rstrip("/") != OIDC_ISSUER.rstrip("/"):
        raise RuntimeError("OIDC issuer mismatch between configuration and discovery document")

    _oidc_config_cache.update(config)
    return _oidc_config_cache


def get_jwks():
    """Fetch and cache the JWKS (JSON Web Key Set) from the provider."""
    now = time.time()
    if _jwks_cache["keys"] and (now - _jwks_cache["fetched_at"]) < JWKS_CACHE_TTL:
        return _jwks_cache["keys"]

    oidc_config = get_oidc_config()
    resp = requests.get(oidc_config["jwks_uri"], timeout=10)
    resp.raise_for_status()
    jwks = resp.json()

    _jwks_cache["keys"] = jwks
    _jwks_cache["fetched_at"] = now
    return jwks


def decode_id_token(id_token, nonce):
    """Decode and validate the ID token using the provider's JWKS."""
    jwks = get_jwks()
    oidc_config = get_oidc_config()

    try:
        unverified_header = jwt.get_unverified_header(id_token)
    except JWTError as e:
        raise ValueError(f"Invalid ID token header: {e}")

    kid = unverified_header.get("kid")
    if not kid:
        raise ValueError("ID token header missing 'kid'")

    rsa_key = None
    for key in jwks.get("keys", []):
        if key.get("kid") == kid:
            rsa_key = key
            break

    if not rsa_key:
        # Refresh JWKS cache and retry once (key rotation scenario)
        _jwks_cache["fetched_at"] = 0
        jwks = get_jwks()
        for key in jwks.get("keys", []):
            if key.get("kid") == kid:
                rsa_key = key
                break

    if not rsa_key:
        raise ValueError("Unable to find matching key in JWKS for ID token verification")

    try:
        claims = jwt.decode(
            id_token,
            rsa_key,
            algorithms=["RS256"],
            audience=OIDC_CLIENT_ID,
            issuer=oidc_config["issuer"],
            options={
                "verify_aud": True,
                "verify_iss": True,
                "verify_exp": True,
                "verify_iat": True,
                "verify_at_hash": False,
            },
        )
    except JWTError as e:
        raise ValueError(f"ID token validation failed: {e}")

    # Validate nonce to prevent replay attacks
    if claims.get("nonce") != nonce:
        raise ValueError("ID token nonce mismatch - possible replay attack")

    # Validate authorized party if present
    if "azp" in claims and claims["azp"] != OIDC_CLIENT_ID:
        raise ValueError("ID token authorized party (azp) mismatch")

    return claims


def login_required(f):
    """Decorator to require authentication for a route."""
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if "user" not in session:
            session["next_url"] = request.url
            return redirect(url_for("login"))
        return f(*args, **kwargs)
    return decorated_function


