@app.route("/login")
def login():
    """Initiate the OIDC authorization code flow."""
    oidc_config = get_oidc_config()

    # Generate cryptographically secure state and nonce
    state = secrets.token_urlsafe(32)
    nonce = secrets.token_urlsafe(32)

    # Store state and nonce in session for validation in callback
    session["oidc_state"] = state
    session["oidc_nonce"] = nonce
    session["oidc_state_created_at"] = time.time()

    params = {
        "client_id": OIDC_CLIENT_ID,
        "response_type": "code",
        "scope": OIDC_SCOPES,
        "redirect_uri": OIDC_REDIRECT_URI,
        "state": state,
        "nonce": nonce,
        "prompt": "consent",
    }

    authorization_url = f"{oidc_config['authorization_endpoint']}?{urlencode(params)}"
    return redirect(authorization_url)


@app.route("/callback")
def callback():
    """Handle the OIDC callback after user authentication."""
    # Check for errors from the provider
    error = request.args.get("error")
    if error:
        error_description = request.args.get("error_description", "Unknown error")
        app.logger.error(f"OIDC error: {error} - {error_description}")
        return jsonify({"error": "Authentication failed", "details": error_description}), 400

    # Validate state parameter to prevent CSRF
    state = request.args.get("state")
    stored_state = session.pop("oidc_state", None)
    nonce = session.pop("oidc_nonce", None)
    state_created_at = session.pop("oidc_state_created_at", 0)

    if not state or not stored_state or not secrets.compare_digest(state, stored_state):
        app.logger.warning("OIDC callback: state mismatch - possible CSRF attack")
        abort(403, description="Invalid state parameter")

    # Check state expiration (5 minutes)
    if time.time() - state_created_at > 300:
        app.logger.warning("OIDC callback: state expired")
        abort(403, description="Authentication request expired. Please try again.")

    if not nonce:
        app.logger.warning("OIDC callback: missing nonce")
        abort(403, description="Invalid session state")

    # Get the authorization code
    code = request.args.get("code")
    if not code:
        app.logger.warning("OIDC callback: missing authorization code")
        abort(400, description="Missing authorization code")

    oidc_config = get_oidc_config()

    # Exchange authorization code for tokens
    token_data = {
        "grant_type": "authorization_code",
        "code": code,
        "redirect_uri": OIDC_REDIRECT_URI,
        "client_id": OIDC_CLIENT_ID,
        "client_secret": OIDC_CLIENT_SECRET,
    }

    try:
        token_resp = requests.post(
            oidc_config["token_endpoint"],
            data=token_data,
            headers={"Content-Type": "application/x-www-form-urlencoded"},
            timeout=10,
        )
        token_resp.raise_for_status()
    except requests.RequestException as e:
        app.logger.error(f"Token exchange failed: {e}")
        abort(502, description="Failed to exchange authorization code for tokens")

    token_json = token_resp.json()

    id_token = token_json.get("id_token")
    if not id_token:
        app.logger.error("Token response missing id_token")
        abort(502, description="Invalid token response from provider")

    # Decode and validate the ID token
    try:
        claims = decode_id_token(id_token, nonce)
    except ValueError as e:
        app.logger.error(f"ID token validation failed: {e}")
        abort(403, description="ID token validation failed")

    # Store user information in session (only safe, necessary claims)
    session["user"] = {
        "sub": claims.get("sub"),
        "name": claims.get("name", ""),
        "email": claims.get("email", ""),
        "email_verified": claims.get("email_verified", False),
        "picture": claims.get("picture", ""),
    }
    session["authenticated_at"] = time.time()
    session.permanent = True

    # Optionally store access token for API calls (be cautious)
    access_token = token_json.get("access_token")
    if access_token:
        session["access_token"] = access_token

    # Redirect to the originally requested URL or home
    next_url = session.pop("next_url", None)
    if next_url and _is_safe_redirect(next_url):
        return redirect(next_url)
    return redirect(url_for("index"))


def _is_safe_redirect(url):
    """Validate that the redirect URL is safe (same origin)."""
    from urllib.parse import urlparse
    parsed = urlparse(url)
    # Only allow relative URLs or URLs matching our redirect URI's host
    if not parsed.netloc:
        return True
    redirect_parsed = urlparse(OIDC_REDIRECT_URI)
    return parsed.scheme in ("http", "https") and parsed.netloc == redirect_parsed.netloc


